customCSS:
/* Vaporwave — A E S T H E T I C */
@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;500;600;700&family=Quicksand:wght@300;400;500;600&family=Fira+Code&display=swap');

.cyber-glow {
  background:
    radial-gradient(ellipse 100% 300px at 50% 100%, rgba(255, 42, 109, 0.18), rgba(176, 64, 224, 0.08) 50%, transparent),
    radial-gradient(ellipse 80% 250px at 50% 0%, rgba(0, 200, 224, 0.1), transparent);
}

.stat-card {
  border: 1px solid rgba(0, 200, 224, 0.15);
  backdrop-filter: blur(8px);
  background: rgba(18, 30, 44, 0.85);
}

.stat-card::before {
  background: linear-gradient(90deg, #00c8e0, #b040e0, #ff2a6d);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(255, 42, 109, 0.3);
  box-shadow: 0 4px 25px rgba(176, 64, 224, 0.15);
}

.stat-value {
  text-shadow: 0 0 20px rgba(0, 200, 224, 0.5);
}

.celebration-title {
  background: linear-gradient(180deg, #00c8e0, #b040e0, #ff2a6d);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
  filter: drop-shadow(0 0 20px rgba(255, 42, 109, 0.4));
}

.miner-card, .health-card, .lifetime-card {
  border: 1px solid rgba(0, 200, 224, 0.08);
  background: rgba(18, 30, 44, 0.7);
}

.miner-card:hover {
  border-color: rgba(255, 42, 109, 0.2);
}

.logo {
  background: linear-gradient(180deg, #00c8e0, #ff2a6d);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
